import pandas as pd

# Creating a data dictionary with some of the most performant assets over the past 10 years
data = {
    "Asset": ["S&P 500", "NASDAQ-100", "Bitcoin", "Gold", "Real Estate (US)", "MSCI Emerging Markets", "US Treasury Bonds"],
    "Average Annual Return (%)": [14.7, 18.4, 230.0, 1.7, 8.5, 4.0, 2.3]
}

# Creating a DataFrame
df = pd.DataFrame(data)

import ace_tools as tools; tools.display_dataframe_to_user(name="Most Performant Assets Over the Past 10 Years", dataframe=df)

df

